#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,x,y;        cin>>n>>x>>y;        vector<ll>p;        vector<ll>b;        for(int i=0;i<n;i++){            ll a;            cin>>a;            if(i>=x && i<y){                b.push_back(a);            }            else p.push_back(a);        }        auto min_it=min_element(b.begin(),b.end());        rotate(b.begin(),min_it,b.end());        bool inserted=false;        for(int i=0;i<p.size();i++){            if(p[i]>b[0]&& !inserted){                for(int j=0;j<b.size();j++){                    cout<<b[j]<<" ";                }                inserted=true;            }            cout<<p[i]<<" ";        }                if(!inserted){            for(int j=0;j<b.size();j++){                cout<<b[j]<<" ";            }        }        cout<<endl;    }}